<?php namespace App\Exceptions; use Throwable; use Illuminate\Foundation\Exceptions\Handler as ExceptionHandler; use Illuminate\Http\JsonResponse; use App\Services\Logging\DiagnosticLogger; use App\Traits\ApiResponseTrait; use Symfony\Component\HttpKernel\Exception\HttpExceptionInterface; use Illuminate\Support\Facades\Log; class GlobalExceptionHandler extends ExceptionHandler { use ApiResponseTrait; protected $logger; public function __construct($container, DiagnosticLogger $logger) { parent::__construct($container); $this->logger = $logger; } public function report(Throwable $exception) { if ($this->shouldReport($exception)) { $this->logger->logError('Global Error Captured', [ 'message' => $exception->getMessage(), 'file' => $exception->getFile(), 'line' => $exception->getLine(), 'trace' => $exception->getTraceAsString() ]); if ($this->isCritical($exception)) { $this->notifyCriticalError($exception); } } parent::report($exception); } public function render($request, Throwable $e) { $status = ($e instanceof HttpExceptionInterface) ? $e->getStatusCode() : 500; $message = $this->shouldReturnExceptionMessage($e) ? $e->getMessage() : 'حدث خطأ غير متوقع في النظام، يرجى المحاولة لاحقاً.'; return $this->errorResponse($message, $status); } protected function isCritical(Throwable $e): bool { $criticalExceptions = [\PDOException::class, \Error::class]; foreach ($criticalExceptions as $class) { if ($e instanceof $class) return true; } return false; } protected function notifyCriticalError(Throwable $e): void { Log::emergency('Critical System Failure', ['exception' => $e->getMessage()]); } protected function shouldReturnExceptionMessage(Throwable $e): bool { return config('app.debug') || $e instanceof HttpExceptionInterface; } }